import { createComponent, createRoot, createSignal } from 'solid-js';
import { ComponentModal, ModalType } from './modal';

const activeModalInstances: ModalInstance[] = [];

type ModalInstance = {
  destroy: () => void;
};

export function createModal(options: Omit<ModalType, 'open' | 'preRender'>): ModalInstance {
  let disposeRoot: (() => void) | null = null;
  let setIsOpen: ((v: boolean) => void) | null = null;
  let disposed = false;

  const doClose = (callOnClose: boolean) => {
    if (disposed) return;
    disposed = true;

    setIsOpen?.(false);
    if (callOnClose) options.onClose?.();

    const index = activeModalInstances.indexOf(instance);
    if (index > -1) {
      activeModalInstances.splice(index, 1);
    }

    setTimeout(() => {
      disposeRoot?.();
    }, 150);
  };

  createRoot(root => {
    disposeRoot = root;
    const [isOpen, _setIsOpen] = createSignal(true);
    setIsOpen = _setIsOpen;

    // ComponentModal renders via Portal (ZIndex → Portal) — it mounts itself
    // into document.body internally. We only need to call it inside a reactive
    // root so its signals/effects run; we don't need to insert it anywhere.
    createComponent(ComponentModal, {
      ...options,
      get open() {
        return isOpen();
      },
      preRender: false,
      onClose: () => doClose(true),
    });
  });

  const instance: ModalInstance = {
    destroy: () => doClose(false),
  };

  activeModalInstances.push(instance);
  return instance;
}

export function closeAllModals() {
  const instances = [...activeModalInstances];
  instances.forEach(instance => instance.destroy());
}
